    sceneCfg: {"edges": [{"from": "1", "to": "2"}, {"from": "2", "to": "3"}, {"from": "3", "to": "4"}, {"from": "4", "to": "5"}, {"from": "5", "to": "6"}], "label": "LV FAILURE → ELEVATED JVP", "nodes": [{"id": "1", "label": "↑ LVEDP", "x": 100, "y": 50}, {"id": "2", "label": "Pulmonary HTN", "x": 300, "y": 50}, {"id": "3", "label": "↑ RV Afterload", "x": 500, "y": 50}, {"id": "4", "label": "RV Failure", "x": 500, "y": 150}, {"id": "5", "label": "↑ RA Pressure", "x": 300, "y": 150}, {"id": "6", "label": "Elevated JVP", "x": 100, "y": 150}]},
